### 8. `packages/rest-client-generator/src/generate-crud.ts`

Generates the five CRUD method signatures and their fetch-based implementations.

- `findMany(params?: { skip?: number; take?: number }): Promise<T[]>` → `GET /modelName`
- `findUnique(where: Pick<T, IdField>): Promise<T | null>` → `GET /modelName/:id`
- `create(data: Omit<T, AutoFields>): Promise<T>` → `POST /modelName`
- `update(where: Pick<T, IdField>, data: Partial<Omit<T, AutoFields>>): Promise<T>` → `PUT /modelName/:id`
- `delete(where: Pick<T, IdField>): Promise<T>` → `DELETE /modelName/:id`

Where:
- `IdField` = the name of the field with `isId: true` (fallback to first `isUnique` field).
- `AutoFields` = fields where `isReadOnly: true` or `isGenerated: true` (e.g., `id`, `createdAt`).

```typescript
import type * as DMMF from '@prisma/dmmf'

function getIdField(model: DMMF.Model): string {
  return (
    model.fields.find((f) => f.isId)?.name ??
    model.fields.find((f) => f.isUnique)?.name ??
    'id'
  )
}

function getAutoFields(model: DMMF.Model): string[] {
  return model.fields
    .filter((f) => f.isReadOnly || f.isGenerated)
    .map((f) => f.name)
}

export function generateCrudMethods(model: DMMF.Model): string {
  const name = model.name
  const route = name.toLowerCase()
  const idField = getIdField(model)
  const autoFields = getAutoFields(model)

  const omitAutoFields =
    autoFields.length > 0
      ? `Omit<${name}, ${autoFields.map((f) => `'${f}'`).join(' | ')}>`
      : name

  return `
export function create${name}Client(baseUrl: string) {
  const endpoint = \`\${baseUrl}/${route}\`

  return {
    async findMany(params?: { skip?: number; take?: number }): Promise<${name}[]> {
      const query = params ? '?' + new URLSearchParams(params as Record<string, string>).toString() : ''
      const res = await fetch(\`\${endpoint}\${query}\`)
      return res.json()
    },

    async findUnique(where: Pick<${name}, '${idField}'>): Promise<${name} | null> {
      const res = await fetch(\`\${endpoint}/\${where['${idField}']}\`)
      if (res.status === 404) return null
      return res.json()
    },

    async create(data: ${omitAutoFields}): Promise<${name}> {
      const res = await fetch(endpoint, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
      })
      return res.json()
    },

    async update(where: Pick<${name}, '${idField}'>, data: Partial<${omitAutoFields}>): Promise<${name}> {
      const res = await fetch(\`\${endpoint}/\${where['${idField}']}\`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
      })
      return res.json()
    },

    async delete(where: Pick<${name}, '${idField}'>): Promise<${name}> {
      const res = await fetch(\`\${endpoint}/\${where['${idField}']}\`, {
        method: 'DELETE',
      })
      return res.json()
    },
  }
}
`
}
```

