### 7. `packages/rest-client-generator/src/generate-interface.ts`

Converts a single `DMMF.Model` into a TypeScript `interface` string.

Key logic:
- Iterate `model.fields` filtering to `kind === 'scalar'` or `kind === 'enum'`.
- Relation fields (`kind === 'object'`) are excluded from the REST interface (they are navigation properties that require separate endpoints).
- Map DMMF scalar type names → TypeScript types:

| DMMF `type`  | TypeScript |
|--------------|------------|
| `String`     | `string`   |
| `Boolean`    | `boolean`  |
| `Int`        | `number`   |
| `Float`      | `number`   |
| `BigInt`     | `bigint`   |
| `DateTime`   | `string`   |
| `Decimal`    | `number`   |
| `Json`       | `unknown`  |
| `Bytes`      | `string`   |
| Enum name    | string union generated separately |
| Unknown      | `unknown`  |

- `isList` wraps the type in `Array<…>`.
- `isRequired: false` appends ` | null`.

```typescript
import type * as DMMF from '@prisma/dmmf'

const scalarMap: Record<string, string> = {
  String:   'string',
  Boolean:  'boolean',
  Int:      'number',
  Float:    'number',
  BigInt:   'bigint',
  DateTime: 'string',
  Decimal:  'number',
  Json:     'unknown',
  Bytes:    'string',
}

function fieldToTsType(field: DMMF.Field): string {
  let base: string
  if (field.kind === 'enum') {
    base = field.type  // refer to the generated enum type
  } else {
    base = scalarMap[field.type] ?? 'unknown'
  }
  if (field.isList) base = `Array<${base}>`
  if (!field.isRequired) base = `${base} | null`
  return base
}

export function generateInterface(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind === 'scalar' || f.kind === 'enum')
    .map((f) => `  ${f.name}${f.isRequired ? '' : '?'}: ${fieldToTsType(f)};`)
    .join('\n')

  return `export interface ${model.name} {\n${fields}\n}\n`
}
```

