### 9. `packages/rest-client-generator/src/generate-client.ts`

Assembles the per-model pieces and the top-level `createRestClient` factory into a `FileMap`:

```typescript
import type * as DMMF from '@prisma/dmmf'
import { generateInterface } from './generate-interface'
import { generateCrudMethods } from './generate-crud'

/** Returns a map of { filename → file content } to be written to outputDir. */
export function generateRestClient(dmmf: DMMF.Document): Record<string, string> {
  const models = dmmf.datamodel.models

  // Per-model files (optional split-output style)
  // We choose a single-file output: index.ts
  const header = `// This file is auto-generated by @prisma/rest-client-generator. Do not edit.\n\n`

  const enumBlock = dmmf.datamodel.enums
    .map((e) => {
      const values = e.values.map((v) => `  ${v.name} = '${v.name}',`).join('\n')
      return `export enum ${e.name} {\n${values}\n}\n`
    })
    .join('\n')

  const interfaceBlock = models.map(generateInterface).join('\n')

  const crudBlock = models.map(generateCrudMethods).join('\n')

  const factoryBody = models
    .map((m) => `  ${m.name.toLowerCase()}: create${m.name}Client(baseUrl),`)
    .join('\n')

  const factory = `
export function createRestClient(baseUrl: string) {
  return {
${factoryBody}
  }
}
`

  const content = [header, enumBlock, interfaceBlock, crudBlock, factory].join('\n')

  return { 'index.ts': content }
}
```

