import fs from 'node:fs/promises'
import path from 'node:path'

import type { GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'

import { generateRestClient } from './generate-client'

export function onManifest(_config: GeneratorConfig): GeneratorManifest {
  return {
    prettyName: 'Prisma REST Client Generator',
    defaultOutput: 'rest-client',
  }
}

export async function onGenerate(options: GeneratorOptions): Promise<void> {
  const outputDir = options.generator.output?.value ?? 'rest-client'
  const resolvedOutputDir = path.isAbsolute(outputDir)
    ? outputDir
    : path.resolve(path.dirname(options.schemaPath), outputDir)

  await fs.mkdir(resolvedOutputDir, { recursive: true })

  const files = generateRestClient(options.dmmf)

  await Promise.all(
    Object.entries(files).map(([filename, content]) =>
      fs.writeFile(path.join(resolvedOutputDir, filename), content, 'utf-8'),
    ),
  )
}

