import type * as DMMF from '@prisma/dmmf'

const scalarMap: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  BigInt: 'bigint',
  DateTime: 'string',
  Decimal: 'number',
  Json: 'unknown',
  Bytes: 'string',
}

function fieldToTsType(field: DMMF.Field): string {
  let base: string
  if (field.kind === 'enum') {
    base = field.type
  } else {
    base = scalarMap[field.type] ?? 'unknown'
  }
  if (field.isList) base = `Array<${base}>`
  if (!field.isRequired) base = `${base} | null`
  return base
}

/** Generates a TypeScript interface declaration string for a single Prisma model. */
export function generateInterface(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind === 'scalar' || f.kind === 'enum')
    .map((f) => `  ${f.name}${f.isRequired ? '' : '?'}: ${fieldToTsType(f)};`)
    .join('\n')

  return `export interface ${model.name} {\n${fields}\n}\n`
}

